" RAP: Basic behavior definition (2-3 weeks total effort)
managed implementation in class zbp_vendor_approval unique;

define behavior for ZI_VendorApproval
  alias Vendor
  persistent table zvendor_appr
  draft table zvendor_appr_d
  lock master
  total etag LastChangedAt
{
  field (readonly) VendorId;
  create; update; delete;
  draft action Edit;
  draft action Activate;
  action approve result [1] $self;
  validation checkMandatoryFields on save { create; update; }
}
